var e=JSON.parse(`[{"id":"L2_1","type":"subtitle","speaker":null,"text":{"KOREA":"몇 시간 뒤","JPN":"数時間後","ENG":"A few hours later","TWN":"幾小時後"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L7_1","type":"dialog","speaker":"SOLDIER_ADMIN_WHITE_NULL","text":{"KOREA":"시니어님, 제2 탐험대로부터 연락이 왔습니다.","JPN":"シニア、第2探検隊から連絡がありました。","ENG":"Senior, a report has come in from the Second Expeditionary Force.","TWN":"你好，Senior，第二探險隊發來消息了。"},"stage":{"bg":"COUNTERSIDE_JUNGLE","bgm":"THEMA_CITY_CAMPAMENTO","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOLDIER_ADMIN_WHITE_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_COMBAT_ALL_FOOT_STEP_LANDING_SMALL_02"},{"id":"L8_1","type":"dialog","speaker":"SOLDIER_ADMIN_WHITE_NULL","text":{"KOREA":"지시하신 대로, 에어리어 알파, 세타… 모두 탐색을 마쳤습니디만…….","JPN":"ご指示通り、エリアアルファ、シータ……すべて探索を終えましたが……","ENG":"Per your orders, they've finished scouting Areas Alpha and Theta... but...","TWN":"按照指示，區域阿爾法、希塔……都已經探索完畢……"},"stage":{"bg":"COUNTERSIDE_JUNGLE","bgm":"THEMA_CITY_CAMPAMENTO","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOLDIER_ADMIN_WHITE_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"SOLDIER_ADMIN_WHITE_NULL","text":{"KOREA":"시니어님께서 말씀하신 장소는 특정할 수 없었다고 합니다.","JPN":"シニアが示した場所は特定できなかったとのことです。","ENG":"They couldn't pinpoint the location you mentioned, sir.","TWN":"但沒找到你說的地點。"},"stage":{"bg":"COUNTERSIDE_JUNGLE","bgm":"THEMA_CITY_CAMPAMENTO","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOLDIER_ADMIN_WHITE_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"CAMPAMENTO_ADMIN_OLD_NULL","text":{"KOREA":"흐음, 그런가…….","JPN":"ふむ、そうか……","ENG":"Hmm, I see...","TWN":"嗯，是嗎……？"},"stage":{"bg":"COUNTERSIDE_JUNGLE","bgm":"THEMA_CITY_CAMPAMENTO","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CAMPAMENTO_ADMIN_OLD_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"CAMPAMENTO_ADMIN_OLD_NULL","text":{"KOREA":"그렇다면 역시 이번에도 다다를 수 없는 건가…….","JPN":"ということは、やはり今回もたどり着けないということじゃな……","ENG":"So once again, it seems we can't reach it...","TWN":"這次果然還是無法到達嗎……"},"stage":{"bg":"COUNTERSIDE_JUNGLE","bgm":"THEMA_CITY_CAMPAMENTO","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CAMPAMENTO_ADMIN_OLD_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"WADE_CAMPAMENTO_NULL_NULL","text":{"KOREA":"칸, 천공섬 탐색을 시작한 지 제법 시간이 지났습니다.","JPN":"カン、天空島の探索を始めてから、かなりの時間が経過しました。","ENG":"Khan, it's been quite some time since we began exploring the floating island.","TWN":"坎，開始探索天空島已經有一段時間了。"},"stage":{"bg":"COUNTERSIDE_JUNGLE","bgm":"THEMA_CITY_CAMPAMENTO","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"WADE_CAMPAMENTO_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"WADE_CAMPAMENTO_NULL_NULL","text":{"KOREA":"카운터인 저는 그렇다 쳐도, 대원들의 이터니움 실드와 공기통이 한계입니다.","JPN":"カウンターの私はともかく、隊員たちのエタニウムシールドと酸素ボンベはもう限界です。","ENG":"I may endure it as a Counter, but the squad's Eternium shields and air tanks are reaching their limits.","TWN":"我是制裁者無所謂，但隊員們的永恆之金盾和氧氣瓶已經到極限了。"},"stage":{"bg":"COUNTERSIDE_JUNGLE","bgm":"THEMA_CITY_CAMPAMENTO","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"WADE_CAMPAMENTO_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"WADE_CAMPAMENTO_NULL_NULL","text":{"KOREA":"물자가 부족한 상황에서 고위 침식체와 마주하면 대처가 어렵습니다.","JPN":"物資が不足している状況で、高レベルの侵食体に遭遇すると対処が難しくなります。","ENG":"If we run into high-tier C.O.s with supplies running low, we won't be able to cope.","TWN":"在物資匱乏的情況下，面對高危侵蝕體會很危險。"},"stage":{"bg":"COUNTERSIDE_JUNGLE","bgm":"THEMA_CITY_CAMPAMENTO","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CAMPAMENTO_ADMIN_OLD_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"WADE_CAMPAMENTO_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L18_1","type":"dialog","speaker":"WADE_CAMPAMENTO_NULL_NULL","text":{"KOREA":"이쯤에서 관리국으로 복귀하시죠.","JPN":"この辺で管理局へ帰還しましょう。","ENG":"We should return to the Administration for now.","TWN":"回管理局吧。"},"stage":{"bg":"COUNTERSIDE_JUNGLE","bgm":"THEMA_CITY_CAMPAMENTO","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CAMPAMENTO_ADMIN_OLD_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"WADE_CAMPAMENTO_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L19_1","type":"dialog","speaker":"CAMPAMENTO_ADMIN_OLD_NULL","text":{"KOREA":"슬슬 타임 리미트인가…….","JPN":"そろそろタイムリミットか……","ENG":"So the time limit's upon us...","TWN":"極限了嗎……"},"stage":{"bg":"COUNTERSIDE_JUNGLE","bgm":"THEMA_CITY_CAMPAMENTO","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CAMPAMENTO_ADMIN_OLD_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"WADE_CAMPAMENTO_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L20_1","type":"dialog","speaker":"CAMPAMENTO_ADMIN_OLD_NULL","text":{"KOREA":"알겠네. 아쉽지만 어쩔 수 없지. 기회가 오늘만 있는 것도 아니니까.","JPN":"分かった。残念だが仕方あるまい。チャンスが今日しかないわけでもないからのう。","ENG":"Very well. A shame, but there'll be other chances.","TWN":"好吧。雖然很可惜，但也沒辦法。以後還有機會。"},"stage":{"bg":"COUNTERSIDE_JUNGLE","bgm":"THEMA_CITY_CAMPAMENTO","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CAMPAMENTO_ADMIN_OLD_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"WADE_CAMPAMENTO_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L22_1","type":"dialog","speaker":"CAMPAMENTO_ADMIN_OLD_NULL","text":{"KOREA":"자자, 오늘 탐험은 여기까지라네!","JPN":"さあ、今日の探検はここまでじゃ！","ENG":"All right, we'll end today's expedition here!","TWN":"好了，今天的探險就到這裡！"},"stage":{"bg":"COUNTERSIDE_JUNGLE","bgm":"THEMA_CITY_CAMPAMENTO","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CAMPAMENTO_ADMIN_OLD_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L23_1","type":"dialog","speaker":"CAMPAMENTO_ADMIN_OLD_NULL","text":{"KOREA":"모두 수고했네. 탐험 대원들은 지상으로 돌아갈 준비를……","JPN":"皆、ご苦労じゃった。探検隊員は地上に戻る準備を……","ENG":"Good work, everyone. Prepare to return to the surface–","TWN":"大家辛苦了，準備返回地面……"},"stage":{"bg":"COUNTERSIDE_JUNGLE","bgm":"THEMA_CITY_CAMPAMENTO","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CAMPAMENTO_ADMIN_OLD_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"CAMPAMENTO_ADMIN_OLD_NULL","text":{"KOREA":"음!?","JPN":"む！？","ENG":"Hm?!","TWN":"嗯！?"},"stage":{"bg":"COUNTERSIDE_JUNGLE","bgm":"THEMA_CITY_CAMPAMENTO","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CAMPAMENTO_ADMIN_OLD_NULL","face":"UNIT_SURPRISE"},"R":null}},"sfx":"FX_COMBAT_ALL_MAGIC_SPELL_DARK_17"},{"id":"L27_1","type":"dialog","speaker":"WADE_CAMPAMENTO_NULL_NULL","text":{"KOREA":"무슨 일이십니까?","JPN":"どうされました？","ENG":"What is it?","TWN":"有什麼事嗎？"},"stage":{"bg":"COUNTERSIDE_JUNGLE","bgm":"THEMA_CITY_CAMPAMENTO","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CAMPAMENTO_ADMIN_OLD_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"WADE_CAMPAMENTO_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L28_1","type":"dialog","speaker":"CAMPAMENTO_ADMIN_OLD_NULL","text":{"KOREA":"화살촉이 반응하고 있어……?","JPN":"矢じりが反応しておる……？","ENG":"The arrowhead is reacting...?","TWN":"箭矢有反應……？"},"stage":{"bg":"COUNTERSIDE_JUNGLE","bgm":"THEMA_CITY_CAMPAMENTO","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CAMPAMENTO_ADMIN_OLD_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"WADE_CAMPAMENTO_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L29_1","type":"dialog","speaker":"CAMPAMENTO_ADMIN_OLD_NULL","text":{"KOREA":"그, 그렇다면… 설마……!?","JPN":"と、ということは……まさか……！？","ENG":"C-could it be...? No, impossible...?!","TWN":"難…難道是…？！"},"stage":{"bg":"COUNTERSIDE_JUNGLE","bgm":"THEMA_CITY_CAMPAMENTO","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CAMPAMENTO_ADMIN_OLD_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"WADE_CAMPAMENTO_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L31_1","type":"dialog","speaker":"WADE_CAMPAMENTO_NULL_NULL","text":{"KOREA":"칸! 갑자기 어디 가십니까!","JPN":"カン！　急にどこに行くのですか！","ENG":"Khan! Where are you going all of a sudden?!","TWN":"坎！你要去哪裡！"},"stage":{"bg":"COUNTERSIDE_JUNGLE","bgm":"THEMA_CITY_CAMPAMENTO","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"WADE_CAMPAMENTO_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L32_1","type":"dialog","speaker":"WADE_CAMPAMENTO_NULL_NULL","text":{"KOREA":"제기랄, 저 빌어먹을 노인네가 또……!","JPN":"ちくしょう、あのクソじじい……またか！","ENG":"Damn it, that blasted geezer is at it again...!","TWN":"該死的，那個老傢伙又……！"},"stage":{"bg":"COUNTERSIDE_JUNGLE","bgm":"THEMA_CITY_CAMPAMENTO","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"WADE_CAMPAMENTO_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"WADE_CAMPAMENTO_NULL_NULL","text":{"KOREA":"시니어님을 모시고 오겠다! 모든 대원은 현재 위치를 사수하고, 잠시 대기하도록……!","JPN":"シニアを連れてくる！　全隊員は持ち場を守り、しばらく待機するように……！","ENG":"I'll bring the Senior back! All units, hold your positions and stand by...!","TWN":"我去找Senior！所有隊員堅守崗位等我回來…！"},"stage":{"bg":"COUNTERSIDE_JUNGLE","bgm":"THEMA_CITY_CAMPAMENTO","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"WADE_CAMPAMENTO_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"CAMPAMENTO_ADMIN_OLD_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"FOREST_NORMAL","bgm":"THEMA_CITY_CAMPAMENTO","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CAMPAMENTO_ADMIN_OLD_NULL","face":"UNIT_SURPRISE"},"R":null}},"sfx":"FX_COMBAT_ALL_MAGIC_SPELL_DARK_17"},{"id":"L39_1","type":"dialog","speaker":"CAMPAMENTO_ADMIN_OLD_NULL","text":{"KOREA":"마, 말도 안 돼… 화살촉의 떨림이 멈추지 않아…….","JPN":"ま、まさか……矢じりの震えが止まらん……","ENG":"I-impossible... the arrowhead's trembling won't stop...","TWN":"怎，怎麼可能…箭矢一直在動……"},"stage":{"bg":"FOREST_NORMAL","bgm":"THEMA_CITY_CAMPAMENTO","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L40_1","type":"dialog","speaker":"CAMPAMENTO_ADMIN_OLD_NULL","text":{"KOREA":"그렇다면… 이곳 어딘가에…….","JPN":"つまり……このどこかに……","ENG":"Then that means... somewhere here...","TWN":"那樣的話……就在這附近的某個地方……"},"stage":{"bg":"FOREST_NORMAL","bgm":"THEMA_CITY_CAMPAMENTO","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L42_1","type":"dialog","speaker":"CAMPAMENTO_ADMIN_OLD_NULL","text":{"KOREA":"어디냐… 대체 어디 있는 게냐……","JPN":"どこじゃ……いったいどこにあるんじゃ……","ENG":"Where is it...? Where could it be...?","TWN":"到底……在哪裡……？"},"stage":{"bg":"FOREST_NORMAL","bgm":"THEMA_CITY_CAMPAMENTO","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CAMPAMENTO_ADMIN_OLD_NULL","face":"UNIT_SERIOUS"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L43_1","type":"dialog","speaker":"CAMPAMENTO_ADMIN_OLD_NULL","text":{"KOREA":"음!?","JPN":"む！？","ENG":"Hm?!","TWN":"嗯！？"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CAMPAMENTO_ADMIN_OLD_NULL","face":"UNIT_HATE"},"R":null}},"sfx":"FX_COMBAT_ALL_MAGIC_SPELL_DARK_17"},{"id":"L45_1","type":"dialog","speaker":"WADE_CAMPAMENTO_NULL_NULL","text":{"KOREA":"칸! 여기서 뭐하시는 겁니까! 관리국으로 돌아가기로 하지 않았습니까……!","JPN":"カン！　何をしているんですか！　管理局に戻ると言ったではないですか……！","ENG":"Khan! What are you doing out here?! We agreed to return to the Administration...!","TWN":"坎！你在這裡做什麼！不是說好要回管理局嗎……！"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"WADE_CAMPAMENTO_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L46_1","type":"dialog","speaker":"CAMPAMENTO_ADMIN_OLD_NULL","text":{"KOREA":"웨이드! 이걸 보게! 화살촉이 반응하고 있어!","JPN":"ウェイド！　これを見ろ！　矢じりが反応しておる！","ENG":"Wade! Look! The arrowhead's reacting!","TWN":"韋德！快看這個！箭矢在反應！"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CAMPAMENTO_ADMIN_OLD_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"WADE_CAMPAMENTO_NULL_NULL","text":{"KOREA":"잠깐, 화살촉이라고요……?","JPN":"矢じりですと……？","ENG":"Huh? The arrowhead...?","TWN":"等等，箭矢……？"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"WADE_CAMPAMENTO_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"CAMPAMENTO_ADMIN_OLD_NULL","text":{"KOREA":"내 연구에 따르면, 이 화살촉은 황금향에 들어갈 수 있는 열쇠 역할을 하는 물건이라네!","JPN":"ワシの研究によると、この矢じりは黄金郷に入るための鍵の役割をする！","ENG":"My research shows this arrowhead is the key to entering the Golden Vale!","TWN":"根據我的研究，這支箭矢是進入黃金城的鑰匙。"},"stage":{"bg":"FOREST_NORMAL","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CAMPAMENTO_ADMIN_OLD_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"WADE_CAMPAMENTO_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L1_1","type":"dialog","speaker":"CAMPAMENTO_ADMIN_OLD_NULL","text":{"KOREA":"그 화살촉이 반응하고 있다는 건, 이곳 어딘가 황금향이 숨겨져 있다는 뜻이지!","JPN":"その矢じりが反応を示しているということは、この近くに黄金郷があるという意味なんじゃ！","ENG":"If it's reacting, it means the Golden Vale is hidden somewhere here!","TWN":"既然有反應，就代表這一帶就藏著黃金城！"},"stage":{"bg":"FOREST_NORMAL","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CAMPAMENTO_ADMIN_OLD_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"WADE_CAMPAMENTO_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L2_1","type":"dialog","speaker":"WADE_CAMPAMENTO_NULL_NULL","text":{"KOREA":"하지만 평소랑 다를 것 없는 침식지대 아닙니까?","JPN":"ですが、いつもと変わらない侵食地帯に見えますが？","ENG":"But isn't this just another Corrupted Area like any other?","TWN":"但這不就是一般的侵蝕地帶嗎？"},"stage":{"bg":"FOREST_NORMAL","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CAMPAMENTO_ADMIN_OLD_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"WADE_CAMPAMENTO_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L3_1","type":"dialog","speaker":"WADE_CAMPAMENTO_NULL_NULL","text":{"KOREA":"대체 이곳 어디에 황금향이…….","JPN":"いったいどこに黄金郷が……","ENG":"Where in this place could a Golden Vale possibly–","TWN":"哪裡有什麼黃金城……"},"stage":{"bg":"FOREST_NORMAL","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CAMPAMENTO_ADMIN_OLD_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"WADE_CAMPAMENTO_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L4_1","type":"dialog","speaker":"CAMPAMENTO_ADMIN_OLD_NULL","text":{"KOREA":"쯧, 자네는 나를 따라다닌 게 10년이나 됐는데, 아직도 감을 못 잡는군!","JPN":"ちっ、ワシと一緒に働いて10年も経つというのに、まだ分からんのか！","ENG":"Tch, you've followed me for ten years and still haven't learned a thing!","TWN":"嘖，跟了我十年，還是抓不到訣竅。"},"stage":{"bg":"FOREST_NORMAL","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CAMPAMENTO_ADMIN_OLD_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"WADE_CAMPAMENTO_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L5_1","type":"dialog","speaker":"CAMPAMENTO_ADMIN_OLD_NULL","text":{"KOREA":"카운터로서는 뛰어나지만, 트레저 헌터로서는 소질이 부족해.","JPN":"カウンターとしては優秀かもしれんが、トレジャーハンターの素質は足りんのう。","ENG":"You're an excellent Counter, Wade. But as a treasure hunter? Hopeless.","TWN":"你當制裁者的確很優秀，但要當尋寶獵人，天分還差了點。"},"stage":{"bg":"FOREST_NORMAL","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CAMPAMENTO_ADMIN_OLD_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"WADE_CAMPAMENTO_NULL_NULL","face":"UNIT_IDLE"}}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_03"},{"id":"L7_1","type":"dialog","speaker":"CAMPAMENTO_ADMIN_OLD_NULL","text":{"KOREA":"이 바위에 낀 이끼를 잘 보게.","JPN":"この岩に生えている苔を見ろ。","ENG":"Look closely at this moss on the rock.","TWN":"仔細看看這塊石頭上的苔蘚。"},"stage":{"bg":"FOREST_NORMAL","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CAMPAMENTO_ADMIN_OLD_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L8_1","type":"dialog","speaker":"CAMPAMENTO_ADMIN_OLD_NULL","text":{"KOREA":"겉으로는 평범한 이끼처럼 보이지만, 광물처럼 단단하고 날카로운 단면을 가지고 있어.","JPN":"普通の苔のように見えるが、まるで鉱物のように硬く、断面が鋭い。","ENG":"To the eye it seems ordinary, but its cross-section is hard and sharp as minerals.","TWN":"表面看起來是普通苔蘚，但切面卻像礦物一樣堅硬又鋒利。"},"stage":{"bg":"FOREST_NORMAL","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CAMPAMENTO_ADMIN_OLD_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"CAMPAMENTO_ADMIN_OLD_NULL","text":{"KOREA":"이건 절대로 자연적인 성질이라고 할 수 없네.","JPN":"これは決して自然物ではない。","ENG":"That is no natural trait.","TWN":"這絕對不可能是自然形成的。"},"stage":{"bg":"FOREST_NORMAL","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CAMPAMENTO_ADMIN_OLD_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"WADE_CAMPAMENTO_NULL_NULL","text":{"KOREA":"어차피 이곳은 천공 대균열의 영향을 받는 고레벨의 침식지대 아닙니까?","JPN":"ここは天空大亀裂の影響を受けている高レベルの侵食地帯です。","ENG":"This whole place is a high-level Corrupted Area influenced by a Celestial Grand Dimension Crevice, isn't it?","TWN":"反正這裡就是受到天空大峽谷影響的高等級侵蝕地帶吧？"},"stage":{"bg":"FOREST_NORMAL","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CAMPAMENTO_ADMIN_OLD_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"WADE_CAMPAMENTO_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L13_1","type":"dialog","speaker":"WADE_CAMPAMENTO_NULL_NULL","text":{"KOREA":"이런 곳에서 이상현상이 일어날 수 있다는 건, 관리국 교본에도 나와있는 상식이죠.","JPN":"こういった場所では異常現象が起こり得る、管理局の教本にも乗っている常識です。","ENG":"Unnatural phenomena are textbook basics here. It's in the Administration manuals.","TWN":"這種地方出現異常現象也不奇怪，管理局的教科書都有寫。"},"stage":{"bg":"FOREST_NORMAL","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CAMPAMENTO_ADMIN_OLD_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"WADE_CAMPAMENTO_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L14_1","type":"dialog","speaker":"CAMPAMENTO_ADMIN_OLD_NULL","text":{"KOREA":"그럴지도 모르지. 하지만 명심하게, 웨이드.","JPN":"そうかもしれん。だが忘れるな、ウェイド。","ENG":"Perhaps. But remember this, Wade.","TWN":"也許吧……但記住，韋德，"},"stage":{"bg":"FOREST_NORMAL","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CAMPAMENTO_ADMIN_OLD_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"WADE_CAMPAMENTO_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L15_1","type":"dialog","speaker":"CAMPAMENTO_ADMIN_OLD_NULL","text":{"KOREA":"노련한 트레저 헌터라면, 때때로 상식을 뛰어넘어야 하는 법이거든.","JPN":"熟練のトレジャーハンターなら、時には常識を超えてみせねばならんのじゃ。","ENG":"A seasoned treasure hunter must sometimes go beyond common sense.","TWN":"身為資深的尋寶獵人，有時候就是得跳脫常識。"},"stage":{"bg":"FOREST_NORMAL","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CAMPAMENTO_ADMIN_OLD_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"WADE_CAMPAMENTO_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L17_1","type":"dialog","speaker":"CAMPAMENTO_ADMIN_OLD_NULL","text":{"KOREA":"관리국 교본대로, 침식지대에서 온전히 생존할 수 있는 생명체는 존재하지 않아.","JPN":"管理局の教本にあるように、侵食地帯で生存できる生命体はおらん。","ENG":"According to the manuals, no lifeform can truly survive in a Corrupted Area.","TWN":"根據管理局的資料，沒有任何生命體能在侵蝕地帶裡長期生存。"},"stage":{"bg":"FOREST_NORMAL","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CAMPAMENTO_ADMIN_OLD_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"CAMPAMENTO_ADMIN_OLD_NULL","text":{"KOREA":"침식파에 장시간 노출되면, 보통 세포 조직이 광물질처럼 변질되고 말지.","JPN":"侵食波に長時間さらされると、普通の細胞組織は鉱物のように変質してしまうからのう。","ENG":"Exposure to Corruption rays over time usually petrifies tissue into minerals.","TWN":"普通細胞組織暴露太久，會像礦物一樣變質。"},"stage":{"bg":"FOREST_NORMAL","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CAMPAMENTO_ADMIN_OLD_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"CAMPAMENTO_ADMIN_OLD_NULL","text":{"KOREA":"하지만 때때로 특수한 파장의 침식파는 다른 결과를 불러일으키기도 한다네.","JPN":"しかし時に、特殊な波長を持つ侵食波は違う結果をもたらすのじゃ。","ENG":"But on rare occasions, unique wavelengths of Corruption rays yield different results.","TWN":"不過，有時某些特殊波長的侵蝕波，會產生不一樣的結果。"},"stage":{"bg":"FOREST_NORMAL","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CAMPAMENTO_ADMIN_OLD_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"WADE_CAMPAMENTO_NULL_NULL","text":{"KOREA":"다른 결과라고요……?","JPN":"違う結果……？","ENG":"Different results...?","TWN":"不一樣的結果……？"},"stage":{"bg":"FOREST_NORMAL","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CAMPAMENTO_ADMIN_OLD_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"WADE_CAMPAMENTO_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L23_1","type":"dialog","speaker":"CAMPAMENTO_ADMIN_OLD_NULL","text":{"KOREA":"허허, 우리 고향에는 백문불여일견이라는 말이 있지.","JPN":"ホホ、ワシの故郷には百聞は一見にしかずという言葉がある。","ENG":"Ha ha! Where I'm from we say, \\"Seeing once is worth more than hearing a hundred times.\\"","TWN":"呵呵，我們老家有句話叫百聞不如一見。"},"stage":{"bg":"FOREST_NORMAL","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CAMPAMENTO_ADMIN_OLD_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"WADE_CAMPAMENTO_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L24_1","type":"dialog","speaker":"CAMPAMENTO_ADMIN_OLD_NULL","text":{"KOREA":"백 번 설명하는 것보다, 한 번 보여주는 게 더 낫다는 뜻이네.","JPN":"百回説明するよりは、一度見せたほうが早いという意味じゃ。","ENG":"In other words, better to show you.","TWN":"意思就是，與其解釋一百次，不如親眼見一次。"},"stage":{"bg":"FOREST_NORMAL","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CAMPAMENTO_ADMIN_OLD_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"WADE_CAMPAMENTO_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L25_1","type":"dialog","speaker":"WADE_CAMPAMENTO_NULL_NULL","text":{"KOREA":"잠깐, 칸! 지금 무슨 짓을……!","JPN":"待ってください、カン！　何を……！","ENG":"Wait, Khan! What are you–?!","TWN":"喂，坎！你做什麼……！"},"stage":{"bg":"FOREST_NORMAL","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CAMPAMENTO_ADMIN_OLD_NULL","face":"UNIT_IDLE"},"C":{"char_id":"WADE_CAMPAMENTO_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_COMBAT_ALL_MOVEMENT_04"},{"id":"L27_1","type":"dialog","speaker":"WADE_CAMPAMENTO_NULL_NULL","text":{"KOREA":"젠장, 당신 진짜 제정신입니까……?","JPN":"くそ、正気ですか……！？","ENG":"Damn it, are you insane...?","TWN":"該死，你有什麼毛病……？"},"stage":{"bg":"FOREST_NORMAL","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"WADE_CAMPAMENTO_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L28_1","type":"dialog","speaker":"WADE_CAMPAMENTO_NULL_NULL","text":{"KOREA":"여긴 고레벨 침식지대라고요! 작은 상처 하나에 목숨이 오락가락 하는 곳입니다!","JPN":"ここは高レベルの侵食地帯です！　小さな傷でも命を落としかねない場所なんですよ！","ENG":"This is a high-level Corrupted Area! Even a scratch could kill you here!","TWN":"這裡可是高等級侵蝕地帶！一個小傷口都有可能致命！"},"stage":{"bg":"FOREST_NORMAL","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"WADE_CAMPAMENTO_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"CAMPAMENTO_ADMIN_OLD_NULL","text":{"KOREA":"허허, 고작 손가락 하나 짼 걸로, 유난 좀 떨지 말게.","JPN":"ホホ、少し指を切ったくらいで大げさじゃのう。","ENG":"Come now, don't make a fuss over a nicked finger.","TWN":"呵呵，不過劃破個手指而已，別這麼大驚小怪。"},"stage":{"bg":"FOREST_NORMAL","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CAMPAMENTO_ADMIN_OLD_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"WADE_CAMPAMENTO_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L32_1","type":"dialog","speaker":"CAMPAMENTO_ADMIN_OLD_NULL","text":{"KOREA":"그보다 아까 그 이끼를 봐주겠나?","JPN":"それよりだ、苔を見てくれ。","ENG":"Instead, take a look at that moss again.","TWN":"仔細看看剛才那塊苔蘚。"},"stage":{"bg":"FOREST_NORMAL","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CAMPAMENTO_ADMIN_OLD_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"WADE_CAMPAMENTO_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L33_1","type":"dialog","speaker":"WADE_CAMPAMENTO_NULL_NULL","text":{"KOREA":"이끼라고요…? 설마……!?","JPN":"苔……？　まさか……！？","ENG":"Moss...? No way...!","TWN":"苔蘚……？難道……！"},"stage":{"bg":"FOREST_NORMAL","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CAMPAMENTO_ADMIN_OLD_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"WADE_CAMPAMENTO_NULL_NULL","face":"UNIT_IDLE"}}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L34_1","type":"dialog","speaker":"WADE_CAMPAMENTO_NULL_NULL","text":{"KOREA":"이끼가… 피를 머금고 금빛으로 변했어……?","JPN":"苔が……血を含み、金色に変わった……？","ENG":"The moss... soaked up your blood and turned golden...?","TWN":"苔蘚吸收血液後，變成了金色……？"},"stage":{"bg":"FOREST_NORMAL","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CAMPAMENTO_ADMIN_OLD_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"WADE_CAMPAMENTO_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L36_1","type":"dialog","speaker":"CAMPAMENTO_ADMIN_OLD_NULL","text":{"KOREA":"그렇다네…….","JPN":"そうじゃ……","ENG":"Exactly...","TWN":"沒錯。"},"stage":{"bg":"FOREST_NORMAL","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CAMPAMENTO_ADMIN_OLD_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"CAMPAMENTO_ADMIN_OLD_NULL","text":{"KOREA":"다시 말해, 이 이끼는 어떤 특수한 침식파에 장기간 노출되었다는 뜻이지.","JPN":"つまり、この苔はとある特殊な侵食波に長時間さらされていたということじゃ。","ENG":"Which means this moss has been bathed in a unique Corruption ray for ages.","TWN":"這代表這些苔蘚長期暴露在某種特殊的侵蝕波之下。"},"stage":{"bg":"FOREST_NORMAL","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CAMPAMENTO_ADMIN_OLD_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"CAMPAMENTO_ADMIN_OLD_NULL","text":{"KOREA":"생물학적인 성질이 완전히 뒤틀릴 정도로 오랜 시간동안 말이야.","JPN":"生物学的な性質が完全に変異してしまうほど、長い時間をな。","ENG":"Long enough to warp its very biology.","TWN":"生物性質在漫長時間裡已經被完全扭曲了。"},"stage":{"bg":"FOREST_NORMAL","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CAMPAMENTO_ADMIN_OLD_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"WADE_CAMPAMENTO_NULL_NULL","text":{"KOREA":"칸! 그렇다면 설마……?","JPN":"カン！　ということは、まさか……？","ENG":"Khan! Then...","TWN":"坎！難不成——？"},"stage":{"bg":"FOREST_NORMAL","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"WADE_CAMPAMENTO_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"CAMPAMENTO_ADMIN_OLD_NULL","text":{"KOREA":"아직이야. 아직 전율을 느끼기에는 이르네, 웨이드.","JPN":"まだじゃ。戦慄するにはまだ早いぞ、ウェイド。","ENG":"Not yet. Too early to shiver, Wade.","TWN":"還早呢。現在還不是害怕的時候，韋德。"},"stage":{"bg":"FOREST_NORMAL","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CAMPAMENTO_ADMIN_OLD_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"CAMPAMENTO_ADMIN_OLD_NULL","text":{"KOREA":"이건 작은 단서에 불과해. 황금향에 다다르기 위해서는 몇 가지 조건이 더 필요하지.","JPN":"これは小さな手がかりにすぎん。黄金郷にたどり着くためには、まだ幾つかの条件をクリアせねばならん。","ENG":"This is but a small clue. More conditions must be met to reach the Golden Vale.","TWN":"這只是個小線索。想找到黃金城，還有幾道門檻要過。"},"stage":{"bg":"FOREST_NORMAL","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CAMPAMENTO_ADMIN_OLD_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"CAMPAMENTO_ADMIN_OLD_NULL","text":{"KOREA":"서두르게. 어서 탐험대에 연락하여, 지금까지 준비해둔 아티팩트를……","JPN":"急げ。探検隊に連絡し、今まで用意してきたアーティファクトを……","ENG":"Come, quickly. Contact the expedition, gather the Artifacts we prepared–","TWN":"快，通知探險隊，把目前準備好的人造神器……"},"stage":{"bg":"FOREST_NORMAL","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CAMPAMENTO_ADMIN_OLD_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"CAMPAMENTO_ADMIN_OLD_NULL","text":{"KOREA":"으음!?","JPN":"うむ！？","ENG":"Mm?!","TWN":"咦，"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CAMPAMENTO_ADMIN_OLD_NULL","face":"UNIT_SURPRISE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L47_1","type":"dialog","speaker":"CAMPAMENTO_ADMIN_OLD_NULL","text":{"KOREA":"따, 땅이 흔들린다고?","JPN":"じ、地面が揺れているだと？","ENG":"Th-the ground's shaking?","TWN":"地，地在晃……？"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CAMPAMENTO_ADMIN_OLD_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"WADE_CAMPAMENTO_NULL_NULL","face":"UNIT_IDLE"}}},"sfx":"FX_COMBAT_ALL_EARTHQUAKE_06"},{"id":"L48_1","type":"dialog","speaker":"CAMPAMENTO_ADMIN_OLD_NULL","text":{"KOREA":"그럴 리가! 여긴 천공섬이야! 하늘 위의 섬에서 이 정도 규모의 지진이 발생한다는 건……!","JPN":"あり得ん！　ここは天空島じゃ！　空の上にある島でこれほどの地震が発生するはずが……！","ENG":"That's impossible! This is a floating island! For a quake of this scale to hit in the sky...!","TWN":"不可能！這裡可是天空島！怎麼會發生這種規模的地震……！"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CAMPAMENTO_ADMIN_OLD_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"WADE_CAMPAMENTO_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L49_1","type":"dialog","speaker":"WADE_CAMPAMENTO_NULL_NULL","text":{"KOREA":"칸! 저길 보십시오! 하늘이 뭔가가 이상합니다!","JPN":"カン！　あれを見てください！　空の様子がおかしい！","ENG":"Khan! Look up at the sky! Something's wrong!","TWN":"坎！快看那邊！天空出現異常！"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CAMPAMENTO_ADMIN_OLD_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"WADE_CAMPAMENTO_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L50_1","type":"dialog","speaker":"CAMPAMENTO_ADMIN_OLD_NULL","text":{"KOREA":"하, 하늘이라고……?","JPN":"そ、空の様子が……？","ENG":"Th-the sky...?","TWN":"天……天空？"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CAMPAMENTO_ADMIN_OLD_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"WADE_CAMPAMENTO_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L5_1","type":"dialog","speaker":"CAMPAMENTO_ADMIN_OLD_NULL","text":{"KOREA":"저, 저건……!?","JPN":"あ、あれは……！？","ENG":"Th-that's...?!","TWN":"那，那是……！"},"stage":{"bg":"SKY_RED","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CAMPAMENTO_ADMIN_OLD_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"WADE_CAMPAMENTO_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L6_1","type":"dialog","speaker":"WADE_CAMPAMENTO_NULL_NULL","text":{"KOREA":"대균열입니다…! 천공 대균열로부터 알 수 없는 빛이……!","JPN":"大亀裂です……！　天空大亀裂から謎の光が……！","ENG":"A Grand Dimension Crevice...! Unknown light is spilling out of there...!","TWN":"是大峽谷！從天空大峽谷裡發出光芒……"},"stage":{"bg":"SKY_RED","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CAMPAMENTO_ADMIN_OLD_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"WADE_CAMPAMENTO_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L7_1","type":"dialog","speaker":"CAMPAMENTO_ADMIN_OLD_NULL","text":{"KOREA":"대균열이… 점점 커지고 있네……!","JPN":"大亀裂が……段々大きくなっておる……！","ENG":"The Grand Dimension Crevice... it's widening...!","TWN":"裂縫…正在變大……！"},"stage":{"bg":"SKY_RED","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CAMPAMENTO_ADMIN_OLD_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"WADE_CAMPAMENTO_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L8_1","type":"dialog","speaker":"WADE_CAMPAMENTO_NULL_NULL","text":{"KOREA":"균열이 확장하고 있다는 말씀입니까!?","JPN":"亀裂が拡張しているということですか！？","ENG":"You mean the crevice is expanding?!","TWN":"你是說裂縫在擴張！？"},"stage":{"bg":"SKY_RED","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CAMPAMENTO_ADMIN_OLD_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"WADE_CAMPAMENTO_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L9_1","type":"dialog","speaker":"CAMPAMENTO_ADMIN_OLD_NULL","text":{"KOREA":"그, 그래. 이건… 마치…….","JPN":"そ、そうじゃ。これは……まるで……","ENG":"Y-yes. It's... just like...","TWN":"這，這感覺……"},"stage":{"bg":"SKY_RED","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CAMPAMENTO_ADMIN_OLD_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"WADE_CAMPAMENTO_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L12_1","type":"dialog","speaker":"CAMPAMENTO_ADMIN_OLD_NULL","text":{"KOREA":"마치, 여섯 대균열이 이 세계에 처음 나타났을 때와 같은…….","JPN":"まるで、6つの大亀裂がこの世界に初めて現れた時のような……","ENG":"Like when the six Grand Dimension Crevices first appeared in this world...","TWN":"就像六個大峽谷當初第一次出現時一樣……"},"stage":{"bg":"COUNTERSIDE_RED_ADF","bgm":"THEMA_DIVE_EATER","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L13_1","type":"dialog","speaker":"CAMPAMENTO_ADMIN_OLD_NULL","text":{"KOREA":"<color=#ffd34c>관리 실패</color>…….","JPN":"<color=#ffd34c>管理失敗</color>……","ENG":"The <color=#ffd34c>Administration Failure</color>...","TWN":"<color=#ffd34c>管理失敗</color>……"},"stage":{"bg":"COUNTERSIDE_RED_ADF","bgm":"THEMA_DIVE_EATER","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L17_1","type":"dialog","speaker":"SOLDIER_ADMIN_WHITE_NULL","text":{"KOREA":"시니어님! 여기 계셨군요!","JPN":"シニア！　ここにいらっしゃいましたか！","ENG":"Senior! There you are!","TWN":"Senior！原來你在這裡！"},"stage":{"bg":"FOREST_NORMAL","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOLDIER_ADMIN_WHITE_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_COMBAT_ALL_FOOT_STEP_LANDING_SMALL_02"},{"id":"L18_1","type":"dialog","speaker":"SOLDIER_ADMIN_WHITE_NULL","text":{"KOREA":"다수의 침식체 무리가 탐험대를 공격하고 있습니다.","JPN":"多數の侵食体の群れが探検隊を攻撃しています。","ENG":"A swarm of C.O.s is attacking the expedition!","TWN":"探險隊遭到大批侵蝕體攻擊！"},"stage":{"bg":"FOREST_NORMAL","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOLDIER_ADMIN_WHITE_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"SOLDIER_ADMIN_WHITE_NULL","text":{"KOREA":"어서 관리국으로 대피하셔야……","JPN":"すぐに管理局に避難を……","ENG":"You must evacuate to the Administration at once...","TWN":"請立刻撤回管理局……"},"stage":{"bg":"FOREST_NORMAL","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOLDIER_ADMIN_WHITE_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"SOLDIER_ADMIN_WHITE_NULL","text":{"KOREA":"어?","JPN":"え？","ENG":"Huh?","TWN":"嗯？"},"stage":{"bg":"FOREST_NORMAL","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOLDIER_ADMIN_WHITE_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"SOLDIER_ADMIN_WHITE_NULL","text":{"KOREA":"어어? 몸이 저절로……?","JPN":"あれ？　体が勝手に……？","ENG":"M-my body's... floating...?","TWN":"等，等一下，我的身體……？"},"stage":{"bg":"SKY_RED","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOLDIER_ADMIN_WHITE_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"SOLDIER_ADMIN_WHITE_NULL","text":{"KOREA":"으, 으아아아아아아아아아아아악────!!","JPN":"う、うわああああああああ────！！","ENG":"Aaahhhhhhh────!!","TWN":"呃，呃啊啊啊啊啊啊啊啊啊啊啊啊────！"},"stage":{"bg":"SKY_RED","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOLDIER_ADMIN_WHITE_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"WADE_CAMPAMENTO_NULL_NULL","text":{"KOREA":"바, 방금 무슨……?","JPN":"い、今のはいったい……？","ENG":"W-what was that...?","TWN":"剛才那是……？"},"stage":{"bg":"FOREST_NORMAL","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CAMPAMENTO_ADMIN_OLD_NULL","face":"UNIT_SURPRISE"},"C":{"char_id":"SOLDIER_ADMIN_WHITE_NULL","face":"UNIT_IDLE"},"R":{"char_id":"WADE_CAMPAMENTO_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L30_1","type":"dialog","speaker":"WADE_CAMPAMENTO_NULL_NULL","text":{"KOREA":"저 녀석, 지면으로 추락하는 것처럼, 갑자기 하늘로 치솟았어……?","JPN":"あいつ、地面に墜落するような動きで、突然空へと浮かび上がったぞ……？","ENG":"He shot upward. Like falling, but into the sky...?","TWN":"那傢伙像搭上擎天飛梭一樣，咻地衝上……？"},"stage":{"bg":"FOREST_NORMAL","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CAMPAMENTO_ADMIN_OLD_NULL","face":"UNIT_SURPRISE"},"C":{"char_id":"SOLDIER_ADMIN_WHITE_NULL","face":"UNIT_IDLE"},"R":{"char_id":"WADE_CAMPAMENTO_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L31_1","type":"dialog","speaker":"CAMPAMENTO_ADMIN_OLD_NULL","text":{"KOREA":"조심하게, 웨이드! 반중력일세!","JPN":"気をつけろ、ウェイド！　反重力じゃ！","ENG":"Stay sharp, Wade! It's anti-gravity!","TWN":"韋德，小心！那是反重力！"},"stage":{"bg":"FOREST_NORMAL","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CAMPAMENTO_ADMIN_OLD_NULL","face":"UNIT_HATE"},"C":{"char_id":"SOLDIER_ADMIN_WHITE_NULL","face":"UNIT_IDLE"},"R":{"char_id":"WADE_CAMPAMENTO_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L32_1","type":"dialog","speaker":"CAMPAMENTO_ADMIN_OLD_NULL","text":{"KOREA":"대균열이 확장하면서, 지금까지 섬을 끌어당기고 있던 반중력장이 훨씬 강해진 거야!","JPN":"大亀裂の拡張により、今まで島を引っ張っていた反重力場が更に強くなったのじゃ！","ENG":"As the Grand Dimension Crevice expands, the anti-gravity field pulling the island has intensified!","TWN":"隨著裂縫擴張，牽引島的反重力場域變得更強！"},"stage":{"bg":"FOREST_NORMAL","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CAMPAMENTO_ADMIN_OLD_NULL","face":"UNIT_IDLE"},"C":{"char_id":"SOLDIER_ADMIN_WHITE_NULL","face":"UNIT_IDLE"},"R":{"char_id":"WADE_CAMPAMENTO_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L33_1","type":"dialog","speaker":"CAMPAMENTO_ADMIN_OLD_NULL","text":{"KOREA":"너무 크게 움직이면, 우리까지 천공 대균열로 빨려 들어가게 될 걸세!","JPN":"動きすぎると、ワシらまで天空大亀裂に吸い込まれてしまう！","ENG":"One wrong move and we'll be dragged into the Celestial Grand Dimension Crevice too!","TWN":"一個不小心，我們也會被吸進去！"},"stage":{"bg":"FOREST_NORMAL","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CAMPAMENTO_ADMIN_OLD_NULL","face":"UNIT_IDLE"},"C":{"char_id":"SOLDIER_ADMIN_WHITE_NULL","face":"UNIT_IDLE"},"R":{"char_id":"WADE_CAMPAMENTO_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L34_1","type":"dialog","speaker":"WADE_CAMPAMENTO_NULL_NULL","text":{"KOREA":"잠깐, 그 말씀은……!","JPN":"待ってください、それはつまり……！","ENG":"Wait, you mean...!","TWN":"你，你的意思是……！"},"stage":{"bg":"FOREST_NORMAL","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CAMPAMENTO_ADMIN_OLD_NULL","face":"UNIT_IDLE"},"C":{"char_id":"SOLDIER_ADMIN_WHITE_NULL","face":"UNIT_IDLE"},"R":{"char_id":"WADE_CAMPAMENTO_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L35_1","type":"dialog","speaker":"WADE_CAMPAMENTO_NULL_NULL","text":{"KOREA":"이대로 가면, 이 천공섬 자체가 대균열로 빨려 들어갈 수도 있다는 뜻 아닙니까!","JPN":"このままだと、この天空島ごと大亀裂に吸い込まれる可能性もあるって意味じゃないですか！","ENG":"At this rate, the entire floating island could be swallowed into the Grand Dimension Crevice!","TWN":"照這情況下去，整座天空島都可能被大峽谷吞噬！"},"stage":{"bg":"FOREST_NORMAL","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CAMPAMENTO_ADMIN_OLD_NULL","face":"UNIT_IDLE"},"C":{"char_id":"SOLDIER_ADMIN_WHITE_NULL","face":"UNIT_IDLE"},"R":{"char_id":"WADE_CAMPAMENTO_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L36_1","type":"dialog","speaker":"CAMPAMENTO_ADMIN_OLD_NULL","text":{"KOREA":"이론상으로는 그렇지! 앞으로 얼마나 여유가 있을지는 모르겠네!","JPN":"理論上はな！　あとどれほどの猶予があるかは分からん！","ENG":"In theory, yes! I can't say how much time we have left!","TWN":"理論上是這樣！我們時間不多了！"},"stage":{"bg":"FOREST_NORMAL","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CAMPAMENTO_ADMIN_OLD_NULL","face":"UNIT_IDLE"},"C":{"char_id":"SOLDIER_ADMIN_WHITE_NULL","face":"UNIT_IDLE"},"R":{"char_id":"WADE_CAMPAMENTO_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L39_1","type":"dialog","speaker":"WADE_CAMPAMENTO_NULL_NULL","text":{"KOREA":"이 고막을 찢는 듯한 비명소리는……!","JPN":"この、鼓膜を引き裂くような悲鳴……!","ENG":"That ear-splitting roar...!","TWN":"這聲尖叫……"},"stage":{"bg":"FOREST_NORMAL","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"WADE_CAMPAMENTO_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"WADE_CAMPAMENTO_NULL_NULL","text":{"KOREA":"제기랄! 이럴 줄 알았습니다! 당신과 같이 있으면 매번 최악의 상황에 휘말린다고요!","JPN":"くそ！　やっぱりあなたといると、いつも最悪の状況に巻き込まれてしまう！","ENG":"Damn it! I knew it! Every time I'm with you, we land in the worst situations!","TWN":"可惡，我就知道會這樣。跟你在一起時，總是會落在最糟糕的局面！"},"stage":{"bg":"FOREST_NORMAL","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"WADE_CAMPAMENTO_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"WADE_CAMPAMENTO_NULL_NULL","text":{"KOREA":"데몰리션 웜입니다……!","JPN":"デモリッションワームです……！","ENG":"It's a Demolition Worm...!","TWN":"爆破蠕蟲……！"},"stage":{"bg":"FOREST_NORMAL","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CAMPAMENTO_ADMIN_OLD_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"WADE_CAMPAMENTO_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L44_1","type":"dialog","speaker":"WADE_CAMPAMENTO_NULL_NULL","text":{"KOREA":"아무래도 우리의 냄새를 맡은 것 같습니다. 앞으로 수분 뒤면, 교전이 발생하겠죠.","JPN":"どうやら私たちの匂いを感知したようです。交戦はもう避けられないかもしれません。","ENG":"It must've caught our scent. We'll be in battle within minutes.","TWN":"牠們已經聞到我們的氣味了，再過幾分鐘勢必會開打。"},"stage":{"bg":"FOREST_NORMAL","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CAMPAMENTO_ADMIN_OLD_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"WADE_CAMPAMENTO_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L45_1","type":"dialog","speaker":"CAMPAMENTO_ADMIN_OLD_NULL","text":{"KOREA":"데몰리션 웜이라고……?","JPN":"デモリッションワームじゃと……？","ENG":"A Demolition Worm...?","TWN":"爆破蠕蟲……？"},"stage":{"bg":"FOREST_NORMAL","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CAMPAMENTO_ADMIN_OLD_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"WADE_CAMPAMENTO_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L46_1","type":"dialog","speaker":"CAMPAMENTO_ADMIN_OLD_NULL","text":{"KOREA":"하늘도 참 무심하군! 하필 황금향을 눈앞에 둔 이 상황에……!","JPN":"なんということじゃ！　よりにもよって黄金郷が目の前だというのに……！","ENG":"The heavens truly mock me! To appear now, when the Golden Vale is within reach...!","TWN":"我的老天…偏偏在這種時候，黃金城就近在眼前……！"},"stage":{"bg":"FOREST_NORMAL","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CAMPAMENTO_ADMIN_OLD_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"WADE_CAMPAMENTO_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L47_1","type":"dialog","speaker":"WADE_CAMPAMENTO_NULL_NULL","text":{"KOREA":"그 황금향인지 뭔지 살아서 구경이라도 하고 싶다면, 떨어지지 마십시오.","JPN":"その黄金郷とやらを生きて目にしたいなら、私のそばから離れないことですね。","ENG":"If you want to live long enough to glimpse your Golden Vale, don't fall.","TWN":"想活著看到黃金城，就跟緊我！"},"stage":{"bg":"FOREST_NORMAL","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CAMPAMENTO_ADMIN_OLD_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"WADE_CAMPAMENTO_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L48_1","type":"dialog","speaker":"WADE_CAMPAMENTO_NULL_NULL","text":{"KOREA":"지금처럼 움직임이 제약되는 상황에, 당신까지 지키면서 승리를 확신할 수 없습니다.","JPN":"動きが制限された状態で、あなたを守りながら勝てる自信はありません。","ENG":"In these conditions, with movement restricted, I can't guarantee victory while protecting you too.","TWN":"現在行動已經受到限制，我沒辦法在保護你同時還確保勝利。"},"stage":{"bg":"FOREST_NORMAL","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CAMPAMENTO_ADMIN_OLD_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"WADE_CAMPAMENTO_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L50_1","type":"dialog","speaker":"WADE_CAMPAMENTO_NULL_NULL","text":{"KOREA":"게다가 천공 대균열의 상태가 심상치 않아요.","JPN":"それに、天空大亀裂の様子が尋常じゃあない。","ENG":"And the Celestial Grand Dimension Crevice's state looks dire.","TWN":"而且天空大峽谷的狀況不太對。"},"stage":{"bg":"FOREST_NORMAL","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"WADE_CAMPAMENTO_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L1_1","type":"dialog","speaker":"WADE_CAMPAMENTO_NULL_NULL","text":{"KOREA":"금방이라도 무언가 좋지 못한 사태가 터질 것 같은… 불길한 느낌이 듭니다.","JPN":"すぐにでも、何かよからぬ事態が起こりそうな……不吉な予感がします。","ENG":"It feels like something disastrous... could erupt at any moment.","TWN":"有種……不祥的預感。感覺很快就會發生什麼不好的事。"},"stage":{"bg":"FOREST_NORMAL","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"WADE_CAMPAMENTO_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"CAMPAMENTO_ADMIN_OLD_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"FOREST_NORMAL","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CAMPAMENTO_ADMIN_OLD_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"CAMPAMENTO_ADMIN_OLD_NULL","text":{"KOREA":"찬란하게 빛나는 태양이 나무뿌리에 가려, 그 빛을 잃어버리게 될 때.","JPN":"燦々と輝く太陽が木の根に隠れ、その光を失う時。","ENG":"When the radiant sun is veiled by roots, its light fading away...","TWN":"當璀璨耀眼的陽光被樹根遮蔽而失去光芒之時，"},"stage":{"bg":"FOREST_NORMAL","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CAMPAMENTO_ADMIN_OLD_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"CAMPAMENTO_ADMIN_OLD_NULL","text":{"KOREA":"하늘이 갈라지며 땅과 구름이 맞닿는 곳, 어딘가에 황금의 도시가 모습을 드러내고.","JPN":"天が切り裂かれ、地と雲が交わる場所、そのどこかに黄金の都市が姿を現し、","ENG":"The heavens will split open, and where earth and cloud meet, a golden city will appear.","TWN":"天空將會裂開，在大地與雲彩交會的地方，黃金城將現身。  "},"stage":{"bg":"FOREST_NORMAL","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CAMPAMENTO_ADMIN_OLD_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"CAMPAMENTO_ADMIN_OLD_NULL","text":{"KOREA":"그 황금향이 남긴 유산이 수많은 이들을 구하게 될지니…….","JPN":"かの地、黄金郷が残した遺産が多くの者を救うであろう……","ENG":"There, the Golden Vale's Legacy will save countless lives...","TWN":"據說，黃金城留下的遺產，將拯救無數的人……"},"stage":{"bg":"FOREST_NORMAL","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CAMPAMENTO_ADMIN_OLD_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"WADE_CAMPAMENTO_NULL_NULL","text":{"KOREA":"칸, 그건……?","JPN":"カン、それは……？","ENG":"Khan, is that...?","TWN":"坎，那是……？"},"stage":{"bg":"FOREST_NORMAL","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CAMPAMENTO_ADMIN_OLD_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"WADE_CAMPAMENTO_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L10_1","type":"dialog","speaker":"CAMPAMENTO_ADMIN_OLD_NULL","text":{"KOREA":"웨이드, 내게는 평생을 바친 업이 있네.","JPN":"ウェイド、ワシには生涯を捧げた仕事がある。","ENG":"Wade, this is the work of my lifetime.","TWN":"韋德，我這一生，有個非完成不可的使命。"},"stage":{"bg":"FOREST_NORMAL","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CAMPAMENTO_ADMIN_OLD_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"WADE_CAMPAMENTO_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L11_1","type":"dialog","speaker":"CAMPAMENTO_ADMIN_OLD_NULL","text":{"KOREA":"억측일지도 모르지만, 어쩌면 지금이 그 예언의 때일지도 모른다는 생각이 드는군.","JPN":"憶測の可能性もあるが、もしかすると今こそが予言の時かもしれん。","ENG":"Call it delusion if you like, but I can't shake the sense this may be the foretold hour.","TWN":"也許只是我的猜測，但我覺得，現在就是那個預言的時刻。"},"stage":{"bg":"FOREST_NORMAL","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CAMPAMENTO_ADMIN_OLD_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"WADE_CAMPAMENTO_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L12_1","type":"dialog","speaker":"CAMPAMENTO_ADMIN_OLD_NULL","text":{"KOREA":"어쨌든 황금향의 단서를 발견한 이상, 나는 반드시 살아 남아야 하네.","JPN":"黄金郷の手がかりを見つけた以上、ワシは必ず生き残らねばならんのじゃ。","ENG":"Now that I've found a clue to the Golden Vale, I must live on.","TWN":"既然已經找到黃金城的線索，我無論如何都得活下來。"},"stage":{"bg":"FOREST_NORMAL","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CAMPAMENTO_ADMIN_OLD_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"WADE_CAMPAMENTO_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L13_1","type":"dialog","speaker":"CAMPAMENTO_ADMIN_OLD_NULL","text":{"KOREA":"그러니 이번에도 이 늙은이를 지켜줄 수 있겠나?","JPN":"だから今回も、この老いぼれを守ってくれぬか？","ENG":"So once more. Will you protect this old man?","TWN":"所以，這次…也可以請你保護好我這老頭子的命嗎？"},"stage":{"bg":"FOREST_NORMAL","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CAMPAMENTO_ADMIN_OLD_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"WADE_CAMPAMENTO_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L14_1","type":"dialog","speaker":"WADE_CAMPAMENTO_NULL_NULL","text":{"KOREA":"아무렇지도 않게 어려운 부탁을 하시는군요.","JPN":"とんでもない頼みをさらっと言いますね。","ENG":"You sure ask for impossible things like they're nothing.","TWN":"……你還真是說得面不改色呢。"},"stage":{"bg":"FOREST_NORMAL","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CAMPAMENTO_ADMIN_OLD_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"WADE_CAMPAMENTO_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L16_1","type":"dialog","speaker":"WADE_CAMPAMENTO_NULL_NULL","text":{"KOREA":"하지만 걱정하지 마십시오.","JPN":"ですが、ご心配なく。","ENG":"But don't worry.","TWN":"不過，別擔心。"},"stage":{"bg":"FOREST_NORMAL","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"WADE_CAMPAMENTO_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"WADE_CAMPAMENTO_NULL_NULL","text":{"KOREA":"10년 전, 기억을 잃고 방황하던 저에게 새로운 삶을 부여한 사람은 당신입니다.","JPN":"10年前、記憶を失って彷徨っていた私に、あなたは新しい人生を与えてくれた。","ENG":"Ten years ago, you gave a wandering, amnesiac man a new life.","TWN":"十年前，是你讓我這個失去記憶、茫然無依的人重獲新生。"},"stage":{"bg":"FOREST_NORMAL","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"WADE_CAMPAMENTO_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"WADE_CAMPAMENTO_NULL_NULL","text":{"KOREA":"전 세계를 떠돌며, 제 이름과 형제의 행방을 찾아주려 애쓰신 분이 바로 당신이죠.","JPN":"世界を駆け巡り、私の名前と兄弟の行方探しに尽力してくれた。","ENG":"You scoured the world to help me find my name and the fate of my brother.","TWN":"你跑遍全世界，為了找回我的名字，還有我兄弟的下落。"},"stage":{"bg":"FOREST_NORMAL","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CAMPAMENTO_ADMIN_OLD_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"WADE_CAMPAMENTO_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L21_1","type":"dialog","speaker":"WADE_CAMPAMENTO_NULL_NULL","text":{"KOREA":"물론, 그때는 당신이 이렇게 대책 없는 인간일 줄은 몰랐습니다만.","JPN":"もちろん、あの頃はあなたがここまでしょうもない人間だとは知りませんでしたが。","ENG":"Granted, I didn't know then you were this reckless.","TWN":"當然，那時我還不知道你是這麼莽撞的人。"},"stage":{"bg":"FOREST_NORMAL","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CAMPAMENTO_ADMIN_OLD_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"WADE_CAMPAMENTO_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L22_1","type":"dialog","speaker":"CAMPAMENTO_ADMIN_OLD_NULL","text":{"KOREA":"허허, 그거 애석한 일이로군.","JPN":"ホホ、それは残念じゃったのう。","ENG":"Ha ha, unfortunate, isn't it?","TWN":"呵呵，真是替你感到遺憾。"},"stage":{"bg":"FOREST_NORMAL","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CAMPAMENTO_ADMIN_OLD_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"WADE_CAMPAMENTO_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L23_1","type":"dialog","speaker":"CAMPAMENTO_ADMIN_OLD_NULL","text":{"KOREA":"그래서? 이 몸을 따르게 된 걸 후회하나?","JPN":"それで？　ワシについて来たことが悔やまれるか？","ENG":"So tell me, do you regret following me?","TWN":"所以呢？你後悔跟著我嗎？"},"stage":{"bg":"FOREST_NORMAL","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CAMPAMENTO_ADMIN_OLD_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"WADE_CAMPAMENTO_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L24_1","type":"dialog","speaker":"WADE_CAMPAMENTO_NULL_NULL","text":{"KOREA":"훗, 그럴리가요.","JPN":"ふっ、まさか。","ENG":"Hmph. Not a chance.","TWN":"哈，怎麼可能。"},"stage":{"bg":"FOREST_NORMAL","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CAMPAMENTO_ADMIN_OLD_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"WADE_CAMPAMENTO_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L26_1","type":"dialog","speaker":"WADE_CAMPAMENTO_NULL_NULL","text":{"KOREA":"대인 위상 방벽 활성화. 포트리스 실드 전개.","JPN":"対人位相防壁活性化。フォートレスシールド展開。","ENG":"Activating phase barrier. Deploying the fortress shield.","TWN":"對人相位屏障啟動。堡壘護盾展開。"},"stage":{"bg":"FOREST_NORMAL","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"WADE_CAMPAMENTO_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_COMBAT_ALL_TECH_12"},{"id":"L27_1","type":"dialog","speaker":"WADE_CAMPAMENTO_NULL_NULL","text":{"KOREA":"캄파멘토 공인 카운터, 웨이드 바르거스.","JPN":"カンパメント公認カウンター、ウェイド・バルガス。","ENG":"Wade Vargas, Official Counter of Campamento.","TWN":"坎帕門托公認制裁者，韋德·巴克斯。"},"stage":{"bg":"FOREST_NORMAL","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"WADE_CAMPAMENTO_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"WADE_CAMPAMENTO_NULL_NULL","text":{"KOREA":"늘 그렇듯, 난공불락의 방패로써 당신과 이 도시를 지키겠습니다.","JPN":"いつものように、難攻不落の盾として、あなたとこの都市を守ります。","ENG":"As always, I'll be the impregnable shield that defends you and this city.","TWN":"我會像往常一樣，用這面堅不可摧的盾牌守護你，還有這座城市。"},"stage":{"bg":"FOREST_NORMAL","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"WADE_CAMPAMENTO_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_COMBAT_ALL_FOOT_STEP_LANDING_BIG"},{"id":"L30_1","type":"dialog","speaker":"WADE_CAMPAMENTO_NULL_NULL","text":{"KOREA":"……마스터 칸.","JPN":"……マスター・カン。","ENG":"...Master Khan.","TWN":"……坎大師。"},"stage":{"bg":"FOREST_NORMAL","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"WADE_CAMPAMENTO_NULL_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};